from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregations = defaultdict(dict)

    # Helper functions for default statistics
    def calculate_count(group_results):
        return len(group_results)

    def calculate_avg_score(group_results):
        if not group_results:
            return 0.0
        total = sum(result.score for result in group_results)
        return total / len(group_results)

    def calculate_max_score(group_results):
        if not group_results:
            return 0.0
        return max(result.score for result in group_results)

    def calculate_min_score(group_results):
        if not group_results:
            return 0.0
        return min(result.score for result in group_results)

    # Iterate through each SearchResult
    for result in search_results:
        # Extract group_by_field value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing field values by assigning to 'unknown' group
        if group_value is None:
            group_value = 'unknown'

        # Get or create group entry
        group_stats = aggregations[group_value]

        # Collect results for this group
        if 'results' not in group_stats:
            group_stats['results'] = []
        group_stats['results'].append(result)

    # Process each group to calculate statistics
    for group_value, group_data in aggregations.items():
        group_results = group_data['results']

        # Calculate default statistics
        group_stats = aggregations[group_value]
        group_stats['count'] = calculate_count(group_results)
        group_stats['avg_score'] = calculate_avg_score(group_results)
        group_stats['max_score'] = calculate_max_score(group_results)
        group_stats['min_score'] = calculate_min_score(group_results)

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                try:
                    # Apply function to the list of results for this group
                    result = func(group_results)
                    group_stats[field_name] = result
                except Exception as e:
                    # Handle potential errors in custom functions
                    group_stats[field_name] = None

    # Convert defaultdict to regular dict before returning
    return dict(aggregations)

